#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

/*
 * Contiguous Memory Allocation - Memory Protection
 * Demonstrates base/limit register approach for process memory protection
 */

#define MEMORY_SIZE 65536 // 64KB total memory
#define MAX_PROCESSES 10

// Memory protection registers for a process
typedef struct {
 unsigned int base_register; // Starting address
 unsigned int limit_register; // Size of allocated memory
 bool valid; // Is process loaded?
 int pid; // Process ID
 unsigned int *memory; // Pointer to process memory space
} ProcessControlBlock;

// Simulated physical memory
static unsigned char physical_memory[MEMORY_SIZE];

// Current process context
static ProcessControlBlock *current_process = NULL;

// Initialize PCB
ProcessControlBlock* create_process(int pid, unsigned int base, unsigned int limit) {
 if (base + limit > MEMORY_SIZE) {
 printf("Error: Process %d exceeds memory bounds!\n", pid);
 return NULL;
 }

 ProcessControlBlock *pcb = (ProcessControlBlock*)malloc(sizeof(ProcessControlBlock));
 if (!pcb) return NULL;

 pcb->pid = pid;
 pcb->base_register = base;
 pcb->limit_register = limit;
 pcb->valid = true;
 pcb->memory = &physical_memory[base];

 return pcb;
}

// Load process into memory (simulate OS loading)
bool load_process(ProcessControlBlock *pcb, const char *data, size_t data_size) {
 if (!pcb || !pcb->valid) return false;

 if (data_size > pcb->limit_register) {
 printf("Error: Data size %zu exceeds limit %u\n", data_size, pcb->limit_register);
 return false;
 }

 // Copy data into process memory space
 memcpy(pcb->memory, data, data_size);
 printf("Process %d loaded at address %u, size %u\n", 
 pcb->pid, pcb->base_register, pcb->limit_register);
 return true;
}

// Context switch - load process into CPU
void context_switch(ProcessControlBlock *pcb) {
 current_process = pcb;
 printf("Context switch: Now running Process %d\n", pcb->pid);
}

// Memory access with protection check
bool legal_address(unsigned int offset) {
 if (!current_process || !current_process->valid) {
 printf("Error: No process running!\n");
 return false;
 }

 // Check against limit register
 if (offset >= current_process->limit_register) {
 printf("SEGMENTATION FAULT!\n");
 printf(" Process %d tried to access offset %u\n", 
 current_process->pid, offset);
 printf(" Base: %u, Limit: %u\n", 
 current_process->base_register, 
 current_process->limit_register);
 printf(" Allowed range: %u to %u\n", 
 current_process->base_register,
 current_process->base_register + current_process->limit_register - 1);
 return false;
 }
 return true;
}

// Read from memory (logical address = offset from base)
unsigned char read_memory(unsigned int offset) {
 if (!legal_address(offset)) {
 return 0; // In real OS, this would trap
 }
 return current_process->memory[offset];
}

// Write to memory (logical address = offset from base)
bool write_memory(unsigned int offset, unsigned char value) {
 if (!legal_address(offset)) {
 return false;
 }
 current_process->memory[offset] = value;
 return true;
}

// Simulate memory compaction
void compact_memory(ProcessControlBlock *processes[], int num_processes) {
 printf("\n=== MEMORY COMPACTION ===\n");
 unsigned int current_addr = 0; // After OS

 for (int i = 0; i < num_processes; i++) {
 if (processes[i] && processes[i]->valid) {
 if (processes[i]->base_register != current_addr) {
 // Move process to new location
 printf("Moving Process %d from %u to %u\n",
 processes[i]->pid, 
 processes[i]->base_register, 
 current_addr);

 // In real OS: update relocation register
 // Here we simulate by updating base
 memmove(&physical_memory[current_addr], 
 &physical_memory[processes[i]->base_register],
 processes[i]->limit_register);

 processes[i]->base_register = current_addr;
 processes[i]->memory = &physical_memory[current_addr];
 }
 current_addr += processes[i]->limit_register;
 }
 }

 printf("Compaction complete! Free space now contiguous.\n");
}

// Display memory map
void display_memory_map(ProcessControlBlock *processes[], int num_processes) {
 printf("\n=== MEMORY MAP ===\n");
 printf("[OS: 0 - 4095]\n");

 for (int i = 0; i < num_processes; i++) {
 if (processes[i] && processes[i]->valid) {
 unsigned int start = processes[i]->base_register;
 unsigned int end = start + processes[i]->limit_register - 1;
 printf("[Process %d: %u - %u] (%u KB)\n",
 processes[i]->pid, start, end, 
 processes[i]->limit_register / 1024);
 }
 }
 printf("==================\n\n");
}

int main() {
 printf("CONTIGUOUS MEMORY ALLOCATION - C DEMONSTRATION\n");
 printf("================================================\n");

 // Initialize memory
 memset(physical_memory, 0, MEMORY_SIZE);

 // Create some processes
 ProcessControlBlock *processes[MAX_PROCESSES] = {NULL};

 // OS occupies first 4KB
 printf("OS loaded at addresses 0-4095\n\n");

 // Load processes with contiguous allocation
 processes[0] = create_process(1, 4096, 8192); // 8KB at 4KB
 processes[1] = create_process(2, 12288, 4096); // 4KB at 12KB
 processes[2] = create_process(3, 16384, 12288); // 12KB at 16KB

 // Load data into processes
 char data1[] = "Hello from Process 1";
 char data2[] = "Process 2 data here";
 char data3[] = "Process 3's important data";

 load_process(processes[0], data1, strlen(data1) + 1);
 load_process(processes[1], data2, strlen(data2) + 1);
 load_process(processes[2], data3, strlen(data3) + 1);

 display_memory_map(processes, MAX_PROCESSES);

 // Switch to process 1 and access memory
 context_switch(processes[0]);
 printf("Reading from offset 0: '%s'\n", (char*)current_process->memory);

 // Try legal access
 printf("\nLegal access at offset 5: '%c'\n", read_memory(5));

 // Try illegal access (beyond limit)
 printf("\nAttempting illegal access at offset 10000:\n");
 read_memory(10000);

 // Demonstrate memory compaction
 // First, "remove" process 2 to create hole
 printf("\n--- Simulating process 2 termination ---\n");
 processes[1]->valid = false; // Process 2 terminates

 display_memory_map(processes, MAX_PROCESSES);

 // Compact memory
 compact_memory(processes, MAX_PROCESSES);

 display_memory_map(processes, MAX_PROCESSES);

 // Cleanup
 for (int i = 0; i < MAX_PROCESSES; i++) {
 free(processes[i]);
 }

 printf("Demo complete!\n");
 return 0;
}

import java.util.*;

/**
 * Contiguous Memory Allocation - Java Implementation
 * Demonstrates First Fit, Best Fit, and Worst Fit allocation strategies
 */

class MemoryHole {
 int startAddress;
 int size;
 String processId;

 public MemoryHole(int startAddress, int size) {
 this.startAddress = startAddress;
 this.size = size;
 this.processId = null; // null means free hole
 }

 public boolean isFree() {
 return processId == null;
 }

 public int getEndAddress() {
 return startAddress + size - 1;
 }

 @Override
 public String toString() {
 if (isFree()) {
 return String.format("[HOLE: %d KB @ %d]", size, startAddress);
 }
 return String.format("[%s: %d KB @ %d-%d]", 
 processId, size, startAddress, getEndAddress());
 }
}

abstract class AllocationStrategy {
 protected String name;

 public AllocationStrategy(String name) {
 this.name = name;
 }

 public String getName() {
 return name;
 }

 // Find the best hole for given size
 public abstract MemoryHole findHole(List<MemoryHole> holes, int size);
}

class FirstFitStrategy extends AllocationStrategy {
 public FirstFitStrategy() {
 super("First Fit");
 }

 @Override
 public MemoryHole findHole(List<MemoryHole> holes, int size) {
 for (MemoryHole hole : holes) {
 if (hole.isFree() && hole.size >= size) {
 return hole;
 }
 }
 return null;
 }
}

class BestFitStrategy extends AllocationStrategy {
 public BestFitStrategy() {
 super("Best Fit");
 }

 @Override
 public MemoryHole findHole(List<MemoryHole> holes, int size) {
 MemoryHole bestHole = null;
 int minRemaining = Integer.MAX_VALUE;

 for (MemoryHole hole : holes) {
 if (hole.isFree() && hole.size >= size) {
 int remaining = hole.size - size;
 if (remaining < minRemaining) {
 minRemaining = remaining;
 bestHole = hole;
 }
 }
 }
 return bestHole;
 }
}

class WorstFitStrategy extends AllocationStrategy {
 public WorstFitStrategy() {
 super("Worst Fit");
 }

 @Override
 public MemoryHole findHole(List<MemoryHole> holes, int size) {
 MemoryHole worstHole = null;
 int maxRemaining = -1;

 for (MemoryHole hole : holes) {
 if (hole.isFree() && hole.size >= size) {
 int remaining = hole.size - size;
 if (remaining > maxRemaining) {
 maxRemaining = remaining;
 worstHole = hole;
 }
 }
 }
 return worstHole;
 }
}

class MemoryManager {
 private List<MemoryHole> holes;
 private int totalMemory;
 private int osSize;

 public MemoryManager(int totalMemory, int osSize) {
 this.totalMemory = totalMemory;
 this.osSize = osSize;
 this.holes = new ArrayList<>();

 // Initialize with one large free hole
 holes.add(new MemoryHole(osSize, totalMemory - osSize));
 }

 public boolean allocate(String processId, int size, AllocationStrategy strategy) {
 MemoryHole selectedHole = strategy.findHole(holes, size);

 if (selectedHole == null) {
 System.out.println("Allocation failed: No suitable hole for " + processId + 
 " (" + size + " KB)");
 return false;
 }

 // Remove the original hole
 holes.remove(selectedHole);

 // Create allocated block
 MemoryHole allocated = new MemoryHole(selectedHole.startAddress, size);
 allocated.processId = processId;
 holes.add(allocated);

 // Create new hole if there's remaining space
 int remainingSize = selectedHole.size - size;
 if (remainingSize > 0) {
 MemoryHole newHole = new MemoryHole(
 selectedHole.startAddress + size, 
 remainingSize
 );
 holes.add(newHole);
 }

 System.out.println(strategy.getName() + ": Allocated " + processId + 
 " (" + size + " KB) at address " + selectedHole.startAddress);

 return true;
 }

 public boolean deallocate(String processId) {
 for (MemoryHole hole : holes) {
 if (!hole.isFree() && hole.processId.equals(processId)) {
 hole.processId = null;
 System.out.println("Deallocated: " + processId);
 mergeHoles();
 return true;
 }
 }
 return false;
 }

 private void mergeHoles() {
 // Sort by start address
 holes.sort(Comparator.comparingInt(h -> h.startAddress));

 List<MemoryHole> merged = new ArrayList<>();

 for (MemoryHole hole : holes) {
 if (merged.isEmpty() || !merged.get(merged.size() - 1).isFree() || !hole.isFree()) {
 merged.add(new MemoryHole(hole.startAddress, hole.size));
 merged.get(merged.size() - 1).processId = hole.processId;
 } else {
 // Merge with previous hole
 MemoryHole prev = merged.get(merged.size() - 1);
 prev.size += hole.size;
 }
 }

 holes = merged;
 }

 public int calculateExternalFragmentation() {
 return holes.stream()
 .filter(MemoryHole::isFree)
 .mapToInt(h -> h.size)
 .sum();
 }

 public int calculateInternalFragmentation() {
 // Internal fragmentation = sum of (allocated partition size - actual process size)
 // Simplified: assume no padding, so this is 0 for variable partitioning
 return 0;
 }

 public void printMemoryMap() {
 System.out.println("\n" + "=".repeat(50));
 System.out.println("MEMORY MAP (" + calculateExternalFragmentation() + " KB free)");
 System.out.println("=".repeat(50));
 System.out.printf("[OS: %d KB @ 0-%d]%n", osSize, osSize - 1);

 // Sort and print
 holes.sort(Comparator.comparingInt(h -> h.startAddress));
 for (MemoryHole hole : holes) {
 System.out.println(" " + hole);
 }
 System.out.println("=".repeat(50) + "\n");
 }
}

public class ContiguousMemoryAllocation {

 public static void main(String[] args) {
 System.out.println("CONTIGUOUS MEMORY ALLOCATION - JAVA DEMONSTRATION");
 System.out.println("=".repeat(50));

 // Test request sizes
 int[] requests = {200, 100, 150, 80, 250, 60};
 String[] processNames = {"P1", "P2", "P3", "P4", "P5", "P6"};

 AllocationStrategy[] strategies = {
 new FirstFitStrategy(),
 new BestFitStrategy(),
 new WorstFitStrategy()
 };

 for (AllocationStrategy strategy : strategies) {
 System.out.println("\n" + "#".repeat(50));
 System.out.println("TESTING: " + strategy.getName().toUpperCase());
 System.out.println("#".repeat(50));

 MemoryManager manager = new MemoryManager(1000, 100);
 manager.printMemoryMap();

 // Allocate processes
 for (int i = 0; i < requests.length; i++) {
 boolean success = manager.allocate(processNames[i], requests[i], strategy);
 if (success) {
 System.out.println("→ Remaining free: " + 
 manager.calculateExternalFragmentation() + " KB");
 }
 }

 manager.printMemoryMap();

 // Deallocate some processes
 System.out.println("--- Deallocating P2 and P4 ---");
 manager.deallocate("P2");
 manager.deallocate("P4");
 manager.printMemoryMap();

 // Try to allocate again
 System.out.println("--- Allocating P7 (180 KB) ---");
 manager.allocate("P7", 180, strategy);
 manager.printMemoryMap();
 }

 // Demonstrate fragmentation
 System.out.println("\n" + "=".repeat(50));
 System.out.println("FRAGMENTATION ANALYSIS");
 System.out.println("=".repeat(50));

 MemoryManager demo = new MemoryManager(1000, 100);
 demo.allocate("P1", 200, new FirstFitStrategy());
 demo.allocate("P2", 200, new FirstFitStrategy());
 demo.allocate("P3", 200, new FirstFitStrategy());
 demo.printMemoryMap();

 demo.deallocate("P2");
 System.out.println("After deallocating P2 (200KB hole created):");
 demo.printMemoryMap();

 System.out.println("External fragmentation: " + 
 demo.calculateExternalFragmentation() + " KB");
 }
}
